-- Admin (id=1) as OWNER of organizations Acme, Beta, Gamma INSERT INTO organization_membership (user_id, organization_id, role, invited_by, joined_at) VALUES (1, (SELECT id FROM organization WHERE slug = 'acme-corp'), 'OWNER', NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 days'), (1, (SELECT id FROM organization WHERE slug = 'beta-industries'), 'OWNER', NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '28 days'), (1, (SELECT id FROM organization WHERE slug = 'gamma-solutions'), 'OWNER', NULL, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '27 days');
